Def:
=If(
Avg({$<[Scorecard Margin $_2Months] *= {"0"}, $(vScorecardMissingLevel),$(vScorecardIgnoreLevel)>}
	Aggr({$<[Scorecard Margin $_2Months] *= {"0"},$(vScorecardIgnoreLevel)>}
    	[Scorecard Margin $_2Months]
        ,$(vScorecardAggrLevel))) = 0,100,

Avg({$<[Scorecard Margin $_2Months] *= {"0"}, $(vScorecardMissingLevel),$(vScorecardIgnoreLevel)>}
	Aggr({$<[Scorecard Margin $_2Months] *= {"0"},$(vScorecardIgnoreLevel)>}
    	[Scorecard Margin $_2Months]
        ,$(vScorecardAggrLevel)))
)

DefExpanded:
=If(
Avg({$<[Scorecard Margin $_2Months] *= {"0"}, [Loan Officer Missing]*={0}, [Branch Missing]*={0},[Loan Officer]*=, [Branch]*=>}
	Aggr({$<[Scorecard Margin $_2Months] *= {"0"},[Loan Officer]*=, [Branch]*=>}
    	[Scorecard Margin $_2Months]
        ,[Loan Officer],[Branch])) = 0,100,

Avg({$<[Scorecard Margin $_2Months] *= {"0"}, [Loan Officer Missing]*={0}, [Branch Missing]*={0},[Loan Officer]*=, [Branch]*=>}
	Aggr({$<[Scorecard Margin $_2Months] *= {"0"},[Loan Officer]*=, [Branch]*=>}
    	[Scorecard Margin $_2Months]
        ,[Loan Officer],[Branch]))
)

Def:
=Avg({$<[Scorecard PullThrough_2Months] *= {">0"}, $(vScorecardMissingLevel),$(vScorecardIgnoreLevel)>}
	Aggr({$<$(vScorecardIgnoreLevel)>}
    	Count({<DateType*={'Application'}, [Date] *= {">=$(=Date(vCurrentDateAsDate-vShotTermPullThroughRange))<=$(=Date(vCurrentDateAsDate))"}, [Active Loan Flag]*={No}, [Pull Through Originated Flag]*={Yes}, [Channel Group]*={'$(vChannelGroup)'}, $(vScorecardMissingLevel),$(vScorecardIgnoreLevel)>}[Loan Number])
		/
		Count({<DateType*={'Application'}, [Date] *= {">=$(=Date(vCurrentDateAsDate-vShotTermPullThroughRange))<=$(=Date(vCurrentDateAsDate))"}, [Active Loan Flag]*={No}, [Channel Group]*={'$(vChannelGroup)'}, $(vScorecardMissingLevel), $(vPTDim)*=,$(vScorecardIgnoreLevel)>}Total<[$(vScorecardActors)],[$(vScorecardEntities)]>[Loan Number])

        ,$(vScorecardAggrLevel)))

DefExpanded:
=Avg({$<[Scorecard PullThrough_2Months] *= {">0"}, [Loan Officer Missing]*={0}, [Branch Missing]*={0},[Loan Officer]*=, [Branch]*=>}
	Aggr({$<[Loan Officer]*=, [Branch]*=>}
    	Count({<DateType*={'Application'}, [Date] *= {">=-<=-"}, [Active Loan Flag]*={No}, [Pull Through Originated Flag]*={Yes}, [Channel Group]*={''}, [Loan Officer Missing]*={0}, [Branch Missing]*={0},[Loan Officer]*=, [Branch]*=>}[Loan Number])
		/
		Count({<DateType*={'Application'}, [Date] *= {">=-<=-"}, [Active Loan Flag]*={No}, [Channel Group]*={''}, [Loan Officer Missing]*={0}, [Branch Missing]*={0}, *=,[Loan Officer]*=, [Branch]*=>}Total<[Loan Officer],[Branch]>[Loan Number])

        ,[Loan Officer],[Branch]))

=Avg({$<[Scorecard TurnTime_2Months] *= {">0"}, [Loan Officer Missing]*={0}, [Branch Missing]*={0},[Loan Officer]*=, [Branch]*=>}
	Aggr(
    {$<[Scorecard TurnTime_2Months] *= {">0"},[Loan Officer]*=, [Branch]*=>}
    	Pow([Scorecard TurnTime_2Months]
        ,-1),[Loan Officer],[Branch]))

