Def:
$(=Pick(Match(vLoanStatus, 'Active', 'Originated', 'All'),

// Active
'[Active Loan Flag]*={Yes},[Lock Expired Flag]*={$(vLock)},[Application $(vMarginToDate)]*={Yes},[Correspondent Channel Flag]={''$(vCorrespondent)''},Channel*={"$(vChannel)"}', 

// Funded
'[Current Loan Status]={"*Originated*"},[$(vDateToggle1) $(vMarginToDate)]={Yes},[Correspondent Channel Flag]={''$(vCorrespondent)''},Channel*={"$(vChannel)"}', 

// All
'[$(vMarginToDate)]={Yes},[Correspondent Channel Flag]={''$(vCorrespondent)''},Channel*={"$(vChannel)"}'))
